steps.script:
() => {
  const vw = window.innerWidth, vh = window.innerHeight;
  const docW = document.documentElement.scrollWidth;
  const horizontalScroll = docW > vw + 1;
  let offenders = [];
  if (horizontalScroll) {
    document.querySelectorAll('body *').forEach(el => {
      if (offenders.length >= 10) return;
      const r = el.getBoundingClientRect();
      if (r.width > 0 && r.right > vw + 2 && getComputedStyle(el).position !== 'fixed') {
        const cls = (typeof el.className === 'string' && el.className.trim()) ? '.' + el.className.trim().split(/\s+/).slice(0, 2).join('.') : '';
        offenders.push(el.tagName.toLowerCase() + cls + ' right=' + Math.round(r.right));
      }
    });
  }
  const imgs = [...document.images].map(im => ({
    src: (im.currentSrc || im.src || '').slice(0, 150),
    nat: [im.naturalWidth, im.naturalHeight],
    rend: [Math.round(im.width), Math.round(im.height)],
    broken: im.complete && im.naturalWidth === 0,
    alt: im.getAttribute('alt'),
  }));
  const brokenImgs = imgs.filter(i => i.broken).map(i => i.src);
  const zeroImgs = imgs.filter(i => (i.rend[0] === 0 || i.rend[1] === 0) && !i.broken).map(i => i.src);
  const altMissing = imgs.filter(i => i.alt === null || i.alt.trim() === '').length;
  const altGeneric = imgs.filter(i => i.alt && /^(me ?\+ ?lia|image|photo|untitled|\S+\.(jpe?g|png|webp|gif))$/i.test(i.alt.trim())).map(i => i.alt).slice(0, 8);
  const distorted = imgs.filter(i => {
    if (!i.nat[0] || !i.nat[1] || !i.rend[0] || !i.rend[1]) return false;
    const na = i.nat[0] / i.nat[1], ra = i.rend[0] / i.rend[1];
    return Math.abs(na - ra) / na > 0.06;
  }).map(i => ({ src: i.src, nat: i.nat, rend: i.rend })).slice(0, 10);
  const upscaled = imgs.filter(i => i.nat[0] && i.rend[0] > i.nat[0] * 1.25).map(i => ({ src: i.src, nat: i.nat, rend: i.rend })).slice(0, 10);
  const hs = [...document.querySelectorAll('h1,h2,h3,h4,h5,h6')].map(h => ({ lvl: +h.tagName[1], text: (h.textContent || '').trim().slice(0, 70) }));
  const h1Count = hs.filter(h => h.lvl === 1).length;
  let skipped = [], prev = 0;
  hs.forEach(h => { if (prev && h.lvl > prev + 1) skipped.push(prev + '->' + h.lvl); prev = h.lvl; });
  let smallText = [], tinyTaps = [];
  if (vw <= 480) {
    [...document.querySelectorAll('p,li,a,span')].slice(0, 500).forEach(el => {
      const t = (el.textContent || '').trim();
      if (t.length > 25) { const fs = parseFloat(getComputedStyle(el).fontSize); if (fs && fs < 14) smallText.push(Math.round(fs) + 'px: ' + t.slice(0, 35)); }
    });
    smallText = [...new Set(smallText)].slice(0, 8);
    [...document.querySelectorAll('a,button,[role=button],input,select')].forEach(el => {
      const r = el.getBoundingClientRect();
      if (r.width > 0 && r.height > 0 && (r.width < 44 || r.height < 44)) {
        tinyTaps.push(Math.round(r.width) + 'x' + Math.round(r.height) + ' ' + ((el.textContent || el.getAttribute('aria-label') || el.tagName) || '').trim().slice(0, 25));
      }
    });
    tinyTaps = [...new Set(tinyTaps)].slice(0, 12);
  }
  const bt = document.body.innerText || '';
  const leaks = {
    lorem: /lorem ipsum/i.test(bt),
    undef: /\bundefined\b/.test(bt),
    translationMissing: /translation missing/i.test(bt),
    liquidRaw: /(\{\{.*?\}\}|\{%.*?%\})/.test(bt),
  };
  const banned = ['effortless', 'elegant', 'curated', 'obsessed', 'must-have', 'put-together', 'daydream'];
  const bannedHits = banned.filter(w => new RegExp('\\b' + w.replace('-', '\\-') + '\\b', 'i').test(bt));
  if (/\bease\b/i.test(bt)) bannedHits.push('ease');
  const emDash = bt.includes('\u2014');
  const ship2day = /\b2\s*days?\b/i.test(bt);
  const returns30 = /\b30[\s-]*day/i.test(bt);
  const springSale = (bt.match(/spring sale/gi) || []).length;
  const soldOut = (bt.match(/sold ?out/gi) || []).length;
  const sel = {
    cartToggle: !!document.querySelector('a[href="/cart"], a[href*="/cart"], [aria-label*="cart" i], [id*="cart" i] a, .header__icon--cart'),
    searchInput: !!document.querySelector('input[type=search], input[name=q]'),
    galleryThumbs: document.querySelectorAll('.product__media-thumbnail, [data-thumbnail], .thumbnail, .product-gallery__thumb').length,
    variantInputs: document.querySelectorAll('variant-radios input, [name^="options"], fieldset input[type=radio]').length,
    accordions: document.querySelectorAll('details, .accordion, [data-accordion]').length,
    addToCart: !!document.querySelector('button[name=add], [data-add-to-cart], .product-form__submit'),
  };
  return { url: location.href, title: document.title, vw, vh, docW, horizontalScroll, offenders,
    imgCount: imgs.length, brokenImgs, zeroImgs, distorted, upscaled, altMissing, altGeneric,
    h1Count, headingOutline: hs.slice(0, 45), skippedHeadingJumps: skipped,
    smallTextMobile: smallText, tinyTaps, leaks, bannedHits, emDash, ship2day, returns30, springSale, soldOut, sel };
}
